int64_t solve(Array<Int64> nums, int64_t k) {
    int n = nums.length;
    if (n == 1) {
        return 0; // Single element array is always balanced
    }

    // Sort the array to easily find min and max
    int64_t *sorted = (int64_t *)malloc(n * sizeof(int64_t));
    for (int i = 0; i < n; i++) {
        sorted[i] = nums[i];
    }
    qsort(sorted, n, sizeof(int64_t), (int (*)(const void*, const void*))strcmp);

    // Try all possible subarrays to find the longest balanced subarray
    int max_len = 1;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            int64_t min_val = sorted[i];
            int64_t max_val = sorted[j];
            if (max_val <= min_val * k) {
                max_len = j - i + 1;
            } else {
                break; // Since array is sorted, no need to check further
            }
        }
    }

    // The minimum number of elements to remove is total elements - max_len
    int64_t result = n - max_len;
    free(sorted);
    return result;
}
