    for (int i = 0; i < n; i++) {
        sorted[i] = nums[i];
    }
    qsort(sorted, n, sizeof(int64_t), (int (*)(const void*, const void*))memcmp);

    // Try all possible subarrays of length >= 1
    int64_t minRemovals = n - 1; // Worst case: remove all but one element

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            int64_t len = j - i;
            if (len == 1) {
                continue; // Single element is always balanced
            }

            int64_t max = sorted[j - 1];
            int64_t min = sorted[i];

            if (max <= min * k) {
                // This subarray is balanced, so we can keep it
                int64_t removals = n - len;
                if (removals < minRemovals) {
                    minRemovals = removals;
                }
            }
        }
    }

    return minRemovals;
}
